+    private static Optional<WrapperRewrite> findWrapperRewrite(List<Statement> statements, int declarationIndex,
+            VariableDeclarator variable) {
+        if (!variable.getInitializer().isPresent() || !variable.getInitializer().get().isObjectCreationExpr()) {
+            return Optional.empty();
+        }
+
+        ObjectCreationExpr creation = variable.getInitializer().get().asObjectCreationExpr();
+        String wrapperName = creation.getType().getNameAsString();
+        if (!"PasswordEncoder".equals(wrapperName) && !"PBEPasswordEncoder".equals(wrapperName)) {
+            return Optional.empty();
+        }
+
+        boolean passwordWrapper = "PasswordEncoder".equals(wrapperName);
+        for (int j = declarationIndex + 1; j < statements.size(); j++) {
+            Statement candidate = statements.get(j);
+            if (!candidate.isExpressionStmt()) {
+                continue;
+            }
+
+            Expression expr = candidate.asExpressionStmt().getExpression();
+            if (!expr.isMethodCallExpr()) {
+                continue;
+            }
+
+            MethodCallExpr call = expr.asMethodCallExpr();
+            if (!call.getScope().isPresent()) {
+                continue;
+            }
+
+            if (!call.getScope().get().isNameExpr() || !call.getScope().get().asNameExpr().getNameAsString()
+                    .equals(variable.getNameAsString())) {
+                continue;
+            }
+
+            if (passwordWrapper && "setPasswordEncryptor".equals(call.getNameAsString()) && call.getArguments().size() == 1) {
+                return Optional.of(new WrapperRewrite(WrapperKind.PASSWORD_ENC, call.getArguments().get(0), candidate));
+            }
