+    private static boolean rewriteRemovedPasswordEncoderType(VariableDeclarator variable) {
+        Type type = variable.getType();
+        if (!type.isClassOrInterfaceType()) {
+            return false;
+        }
+
+        String typeName = type.asClassOrInterfaceType().getNameAsString();
+        if (!"PasswordEncoder".equals(typeName)) {
+            return false;
+        }
+
+        Optional<CompilationUnit> cu = variable.findCompilationUnit();
+        if (cu.isEmpty()) {
+            return false;
+        }
